	// allow customers to set the TaskNumber and Name field
    setTaskNumberAndName : function(current) {
		// change this code to set the value you want as the task name
		return current.taskernumber + ': ' + current.short_description;
	},

	// Set the Tasker Number from the new Task Tree object, add the Primary Assignee, if set.
	setTaskerNumber : function(current) {
		var taskerNumber = '';
		if(current.getDisplayValue('primary_assignee') == ''){
			taskerNumber = current.u_task_tree.u_shared_task_label;
		} else {
			taskerNumber = current.u_task_tree.u_shared_task_label + '-' + current.getDisplayValue('primary_assignee');
		}
		return taskerNumber;
	},

	// Set the Tasker Number from the new Task Tree object, add the Primary Assignee, if set.
	setTaskTreeNumber : function(current) {
		//  Set the Tree Level Tasker Number and use it in all other Tasks
		var date = new Date();
		var datestring = (date.getFullYear().toString()).substr(2) + '-';
		var num = current.number.toString();

		var newNum = '';
		newNum = num.replace('TT', datestring);

		// STRY0091668 - Changed approach for yearly reset
		//newNum = this.checkMaxAgainstYr(newNum);

		return newNum;
	},


	padObjNumber : function(number, digits) {

    var num = number + "";
    while (num.length < digits)
       num = "0" + num;
    return num;
  },

